BEGIN TRANSACTION;
CREATE TABLE Clients (
                         tax_id TEXT PRIMARY KEY,
                         name TEXT NOT NULL,
                         address TEXT,
                         city TEXT,
                         state TEXT,
                         zip_code TEXT);
CREATE TABLE Invoices (
                         invoice_number TEXT PRIMARY KEY,
                         date TEXT,
                         net_worth REAL,
                         vat REAL,
                         gross_worth REAL,
                         client_tax_id TEXT,
                         seller_tax_id TEXT,
                         FOREIGN KEY (client_tax_id) REFERENCES Clients (tax_id),
                         FOREIGN KEY (seller_tax_id) REFERENCES Sellers (tax_id));
CREATE TABLE Sellers (
                         tax_id TEXT PRIMARY KEY,
                         name TEXT NOT NULL,
                         address TEXT,
                         city TEXT,
                         state TEXT,
                         zip_code TEXT,
                         iban TEXT);
COMMIT;
